const withParams = (
  basePayload: Record<string, unknown>,
  params?: Record<string, unknown>,
  target: 'top_level' | 'params' | 'data' = 'top_level'
) => {
  if (!params || Object.keys(params).length === 0) return basePayload;

  const merged = { ...basePayload } as Record<string, unknown>;

  if (target === 'params') {
    const currentParams = typeof merged.params === 'object' && merged.params !== null ? merged.params as Record<string, unknown> : {};
    merged.params = { ...currentParams, ...params };
    return merged;
  }

  if (target === 'data') {
    const currentData = typeof merged.data === 'object' && merged.data !== null ? merged.data as Record<string, unknown> : {};
    merged.data = { ...currentData, ...params };
    return merged;
  }

  return { ...merged, ...params };
};

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const payload = await req.json().catch(() => ({}));
    const { action, params = {} } = payload;

    if (action === 'list_capabilities') {
      const agents = Object.entries(REGISTRY).map(([agent_name, capabilities]) => ({
        agent_name,
        capability_count: capabilities.length,
        capabilities: capabilities.map((cap) => ({
          id: cap.id,
          label: cap.label,
          description: cap.description,
          category: cap.category || 'General',
          tools: cap.tools || [],
          runtime_fields: cap.runtimeFields || [],
          impact: cap.impact,
          function_name: cap.functionName,
          action: cap.payload.action,
        })),
      }));

      return Response.json({
        status: 'success',
        agents,
        summary: {
          total_agents: agents.length,
          total_capabilities: agents.reduce((sum, a) => sum + a.capability_count, 0),
          high_impact_capabilities: agents.flatMap((a) => a.capabilities).filter((c) => c.impact === 'high').length,
        },
      });
    }

    if (action === 'run_capability') {
      const agentName = String(params.agent_name || '').trim();
      const capabilityId = String(params.capability_id || '').trim();
      const runtimeParams = (params.runtime_params || {}) as Record<string, unknown>;

      if (!agentName || !capabilityId) {
        return Response.json({ error: 'agent_name and capability_id are required' }, { status: 400 });
      }

      const capabilities = REGISTRY[agentName] || [];
      const capability = capabilities.find((cap) => cap.id === capabilityId);
      if (!capability) {
        return Response.json({ error: `Capability not found for agent: ${agentName}` }, { status: 404 });
      }

      const requestPayload = withParams(capability.payload, runtimeParams, capability.runtimeTarget || 'top_level');
      const runStartedAt = new Date().toISOString();

      let runData: unknown = null;
      let runStatus: 'completed' | 'failed' = 'completed';
      let runError = '';

      try {
        const runRes = await base44.functions.invoke(capability.functionName, requestPayload);
        runData = runRes.data;
      } catch (err) {
        runStatus = 'failed';
        runError = err instanceof Error ? err.message : 'Unknown execution error';
      }

      await base44.asServiceRole.entities.Activity.create({
        title: `${agentName}: ${capability.label}`,
        description: runStatus === 'completed'
          ? `Capability executed successfully (${capability.id}).`
          : `Capability failed (${capability.id}): ${runError}`,
        type: 'ai_action',
        status: runStatus,
      }).catch(() => null);

      if (runStatus === 'completed') {
        await base44.asServiceRole.entities.Insight.create({
          title: `${agentName} capability completed`,
          description: `${capability.label} executed at ${runStartedAt}.`,
          category: 'recommendation',
          priority: capability.impact === 'high' ? 'high' : 'medium',
          status: 'new',
        }).catch(() => null);
      }

      return Response.json({
        status: runStatus === 'completed' ? 'success' : 'error',
        agent_name: agentName,
        capability: {
          id: capability.id,
          label: capability.label,
          description: capability.description,
          impact: capability.impact,
        },
        function_name: capability.functionName,
        request_payload: requestPayload,
        run_started_at: runStartedAt,
        run_result: runData,
        run_error: runError || null,
      });
    }

    if (action === 'get_agent_blueprint') {
      const agentName = String(params.agent_name || '').trim();
      if (!agentName) {
        return Response.json({ error: 'agent_name is required' }, { status: 400 });
      }

      const capabilities = REGISTRY[agentName] || [];
      if (capabilities.length === 0) {
        return Response.json({ error: `No blueprint for agent: ${agentName}` }, { status: 404 });
      }

      const byCategory = capabilities.reduce((acc: Record<string, Capability[]>, cap) => {
        const cat = cap.category || 'General';
        if (!acc[cat]) acc[cat] = [];
        acc[cat].push(cap);
        return acc;
      }, {});

      return Response.json({
        status: 'success',
        agent_name: agentName,
        categories: Object.entries(byCategory).map(([category, caps]) => ({
          category,
          capability_count: caps.length,
          capabilities: caps.map((cap) => ({
            id: cap.id,
            label: cap.label,
            description: cap.description,
            impact: cap.impact,
            tools: cap.tools || [],
            runtime_fields: cap.runtimeFields || [],
            function_name: cap.functionName,
            action: cap.payload.action,
          })),
        })),
      });
    }
    if (action === 'upgrade_scan') {
      const recentActivities = await base44.asServiceRole.entities.Activity.list('-created_date', 100).catch(() => []);
      const recentInsights = await base44.asServiceRole.entities.Insight.list('-created_date', 60).catch(() => []);

      const scan = await base44.integrations.Core.InvokeLLM({
        prompt: `You are upgrading an AI agent federation. Analyze current operations and propose concrete capability upgrades.

Available capability registry:
${JSON.stringify(REGISTRY)}

Recent activities (${recentActivities.length}):
${JSON.stringify(recentActivities.slice(0, 40).map((a: any) => ({ title: a.title, status: a.status, type: a.type })))}

Recent insights (${recentInsights.length}):
${JSON.stringify(recentInsights.slice(0, 30).map((i: any) => ({ title: i.title, priority: i.priority, category: i.category })))}

Return:
1. top 5 capability gaps
2. top 5 high-impact upgrades
3. which agents need immediate enhancement and why
4. one 7-day execution plan`,
        response_json_schema: {
          type: 'object',
          properties: {
            capability_gaps: { type: 'array', items: { type: 'string' } },
            high_impact_upgrades: { type: 'array', items: { type: 'string' } },
            priority_agents: { type: 'array', items: { type: 'object', properties: { agent: { type: 'string' }, reason: { type: 'string' } } } },
            seven_day_plan: { type: 'array', items: { type: 'string' } },
          },
        },
      });

      return Response.json({ status: 'success', scan });
    }

    return Response.json({ error: `Unknown action: ${action}` }, { status: 400 });
  } catch (error) {
    return Response.json({ error: error instanceof Error ? error.message : 'Unknown error' }, { status: 500 });
  }
});





































